## 4. xterm.js Integration <a name="xtermjs-integration"></a>

xterm.js is a terminal emulator for the browser. It's the core of the portfolio's interactive terminal.

### Installation

```bash
npm install xterm @xterm/addon-fit @xterm/addon-web-links
```

### The Terminal Component

```tsx
// src/components/Terminal.tsx
import { useEffect, useRef, useState } from 'react';
import type { Terminal as XTerminal } from 'xterm';

// ⚠️ CRITICAL: Do NOT import xterm statically at the top level.
// xterm requires browser APIs and will crash during SSR or build.
// Use dynamic imports inside useEffect instead.

interface TerminalProps {
  welcomeMessage?: string;
}

export default function Terminal({ welcomeMessage }: TerminalProps) {
  const terminalRef = useRef<HTMLDivElement>(null);
  const xtermRef = useRef<XTerminal | null>(null);
  const [isReady, setIsReady] = useState(false);

  useEffect(() => {
    // Dynamic import — only runs in browser
    let isMounted = true;

    async function initTerminal() {
      // Dynamically import xterm and addons
      const { Terminal } = await import('xterm');
      const { FitAddon } = await import('@xterm/addon-fit');
      const { WebLinksAddon } = await import('@xterm/addon-web-links');

      // Also dynamically import the CSS
      await import('xterm/css/xterm.css');

      if (!isMounted || !terminalRef.current) return;

      const term = new Terminal({
        cursorBlink: true,
        cursorStyle: 'block',
        fontFamily: '"IBM Plex Mono", "Cascadia Code", monospace',
        fontSize: 14,
        lineHeight: 1.2,
        theme: {
          background: '#0a0a0a',
          foreground: '#00ff41',
          cursor: '#00ff41',
          cursorAccent: '#0a0a0a',
          selectionBackground: '#00ff4140',
          // ANSI colors
          black: '#0a0a0a',
          red: '#ff5555',
          green: '#00ff41',
          yellow: '#f1fa8c',
          blue: '#6272a4',
          magenta: '#ff79c6',
          cyan: '#8be9fd',
          white: '#f8f8f2',
        },
        allowTransparency: true,
        scrollback: 1000,
      });

      // Load addons
      const fitAddon = new FitAddon();
      term.loadAddon(fitAddon);
      term.loadAddon(new WebLinksAddon());

      // Mount to DOM
      term.open(terminalRef.current);
      fitAddon.fit();

      // Handle window resize
      const resizeObserver = new ResizeObserver(() => {
        fitAddon.fit();
      });
      resizeObserver.observe(terminalRef.current);

      // Store reference
      xtermRef.current = term;
      setIsReady(true);

      // Welcome message
      if (welcomeMessage) {
        term.writeln(welcomeMessage);
      }
      term.writeln('');
      term.write('joel@portfolio:~$ ');

      // Handle input
      let currentLine = '';
      term.onKey(({ key, domEvent }) => {
        const char = key;

        if (domEvent.key === 'Enter') {
          term.writeln('');
          handleCommand(term, currentLine.trim());
          currentLine = '';
          term.write('joel@portfolio:~$ ');
        } else if (domEvent.key === 'Backspace') {
          if (currentLine.length > 0) {
            currentLine = currentLine.slice(0, -1);
            term.write('\b \b');
          }
        } else if (char.length === 1 && !domEvent.ctrlKey && !domEvent.altKey) {
          currentLine += char;
          term.write(char);
        }
      });

      // Cleanup
      return () => {
        isMounted = false;
        resizeObserver.disconnect();
        term.dispose();
      };
    }

    initTerminal();

    return () => {
      isMounted = false;
      xtermRef.current?.dispose();
    };
  }, []);

  return (
    <div
      ref={terminalRef}
      className="terminal-container"
      style={{
        width: '100%',
        height: '100%',
        minHeight: '400px',
      }}
    />
  );
}

function handleCommand(term: any, command: string) {
  if (!command) return;

  switch (command) {
    case 'help':
      term.writeln('Available commands:');
      term.writeln('  about     - About me');
      term.writeln('  skills    - Technical skills');
      term.writeln('  projects  - My projects');
      term.writeln('  contact   - Contact info');
      term.writeln('  clear     - Clear screen');
      break;
    case 'clear':
      term.clear();
      break;
    case 'about':
      term.writeln('Joel Thomas — CS student at VIT Chennai');
      term.writeln('AI/ML researcher & full-stack developer');
      break;
    default:
      term.writeln(`Command not found: ${command}`);
      term.writeln('Type "help" for available commands.');
  }
}
```

