## 8. Easter Egg System <a name="easter-egg-system"></a>

The terminal supports hidden commands for fun interactions.

### Architecture

```
User types command
       │
       ▼
commands.ts (dispatcher)
       │
       ├── Built-in commands (help, about, skills, projects, contact, clear)
       │
       └── easter.ts (hidden commands)
            ├── matrix  → Matrix rain animation
            ├── sudo    → "Nice try" message
            ├── hack    → Fake hacking animation
            ├── coffee  → ASCII art coffee cup
            └── rm -rf  → Fake system destruction
```

### commands.ts — Command Dispatcher

```typescript
// src/lib/commands.ts
import type { Terminal } from 'xterm';
import { easterEggCommands } from './easter';

export interface CommandContext {
  term: Terminal;
  args: string[];
}

type CommandHandler = (ctx: CommandContext) => void | Promise<void>;

const commands: Record<string, CommandHandler> = {
  help: ({ term }) => {
    term.writeln('\r\n  \x1b[1;32mAvailable Commands:\x1b[0m\r\n');
    term.writeln('  \x1b[33mabout\x1b[0m      — Who am I?');
    term.writeln('  \x1b[33mskills\x1b[0m     — Technical skills & languages');
    term.writeln('  \x1b[33mprojects\x1b[0m   — Featured projects');
    term.writeln('  \x1b[33mcontact\x1b[0m    — How to reach me');
    term.writeln('  \x1b[33meducation\x1b[0m  — Academic background');
    term.writeln('  \x1b[33mcerts\x1b[0m      — Certifications');
    term.writeln('  \x1b[33mclear\x1b[0m      — Clear the screen');
    term.writeln('  \x1b[33mtheme\x1b[0m      — Change terminal theme');
    term.writeln('');
    term.writeln('  \x1b[90m...and a few hidden commands 😉\x1b[0m');
  },

  about: ({ term }) => {
    term.writeln('\r\n  \x1b[1;36m╔══════════════════════════════════════╗\x1b[0m');
    term.writeln('  \x1b[1;36m║\x1b[0m       Joel Thomas                   \x1b[1;36m║\x1b[0m');
    term.writeln('  \x1b[1;36m║\x1b[0m  AI/ML Engineer & Full-Stack Dev     \x1b[1;36m║\x1b[0m');
    term.writeln('  \x1b[1;36m║\x1b[0m  VIT Chennai • B.Tech CSE (2027)     \x1b[1;36m║\x1b[0m');
    term.writeln('  \x1b[1;36m╚══════════════════════════════════════╝\x1b[0m');
  },

  clear: ({ term }) => {
    term.clear();
  },

  skills: ({ term }) => {
    term.writeln('\r\n  \x1b[1;32m◆ Languages:\x1b[0m Python, TypeScript, Rust, Go, C++, Java, SQL, Bash');
    term.writeln('  \x1b[1;32m◆ AI/ML:\x1b[0m     PyTorch, TensorFlow, Hugging Face, LangChain, Ollama');
    term.writeln('  \x1b[1;32m◆ Web:\x1b[0m       React, Astro, Next.js, Node.js, FastAPI');
    term.writeln('  \x1b[1;32m◆ DevOps:\x1b[0m    Docker, Kubernetes, WSL2, GitHub Actions');
    term.writeln('  \x1b[1;32m◆ Data:\x1b[0m      PostgreSQL, Redis, MongoDB, SQLite');
  },
};

export function executeCommand(term: Terminal, input: string): void {
  const parts = input.trim().split(/\s+/);
  const command = parts[0]?.toLowerCase() || '';
  const args = parts.slice(1);
  const ctx: CommandContext = { term, args };

  // Check built-in commands first
  if (commands[command]) {
    commands[command](ctx);
    return;
  }

  // Check easter eggs
  if (easterEggCommands[command]) {
    easterEggCommands[command](ctx);
    return;
  }

  // Unknown command
  term.writeln(`\r\n  \x1b[31mCommand not found:\x1b[0m ${command}`);
  term.writeln('  Type \x1b[33mhelp\x1b[0m for available commands.');
}
```

### easter.ts — Hidden Commands

```typescript
// src/lib/easter.ts
import type { CommandContext } from './commands';

type CommandHandler = (ctx: CommandContext) => void | Promise<void>;

export const easterEggCommands: Record<string, CommandHandler> = {

  sudo: ({ term }) => {
    term.writeln('\r\n  \x1b[31m[sudo] password for joel: \x1b[0m');
    setTimeout(() => {
      term.writeln('  \x1b[31mNice try. 😏\x1b[0m');
      term.writeln('  \x1b[90mThis incident will be reported.\x1b[0m');
    }, 1500);
  },

  matrix: ({ term }) => {
    term.writeln('\r\n  \x1b[32mFollowing the white rabbit...\x1b[0m\r\n');
    const chars = 'ﾊﾐﾋｰｳｼﾅﾓﾆｻﾜﾂｵﾘｱﾎﾃﾏｹﾒｴｶｷﾑﾕﾗｾﾈｽﾀﾇﾍ012345789Z:.\"=*+-<>¦╌';
    let frames = 0;
    const interval = setInterval(() => {
      let line = '  ';
      for (let i = 0; i < 60; i++) {
        const brightness = Math.random() > 0.5 ? '1;32' : '32';
        line += `\x1b[${brightness}m${chars[Math.floor(Math.random() * chars.length)]}`;
      }
      term.writeln(line + '\x1b[0m');
      frames++;
      if (frames > 15) {
        clearInterval(interval);
        term.writeln('\r\n  \x1b[1;32mWake up, Neo...\x1b[0m');
      }
    }, 100);
  },

  coffee: ({ term }) => {
    term.writeln('\r\n  \x1b[33m     ( (');
    term.writeln('      ) )');
    term.writeln('    .______.');
    term.writeln('    |      |]');
    term.writeln('    \\      /');
    term.writeln('     `----\'\x1b[0m');
    term.writeln('');
    term.writeln('  \x1b[90mHave a coffee break! ☕\x1b[0m');
  },

  hack: ({ term }) => {
    term.writeln('\r\n  \x1b[1;31m[INITIATING HACK SEQUENCE]\x1b[0m');
    const steps = [
      'Bypassing firewall...',
      'Accessing mainframe...',
      'Decrypting passwords...',
      'Downloading everything...',
      'Covering tracks...',
    ];
    steps.forEach((step, i) => {
      setTimeout(() => {
        term.writeln(`  \x1b[31m[${i + 1}/5]\x1b[0m ${step} \x1b[32m✓\x1b[0m`);
        if (i === steps.length - 1) {
          setTimeout(() => {
            term.writeln('\r\n  \x1b[1;33mJust kidding. 😄\x1b[0m');
            term.writeln('  \x1b[90mPlease don\'t actually hack things.\x1b[0m');
          }, 500);
        }
      }, (i + 1) * 800);
    });
  },

  'rm': ({ term, args }) => {
    if (args.includes('-rf') && (args.includes('/') || args.includes('*'))) {
      term.writeln('\r\n  \x1b[1;31m💥 SYSTEM DESTRUCTION IN PROGRESS...\x1b[0m');
      setTimeout(() => {
        term.writeln('  \x1b[31m█████████████████████ 100%\x1b[0m');
        setTimeout(() => {
          term.writeln('\r\n  \x1b[1;32m...just kidding. Everything is fine. 😅\x1b[0m');
          term.writeln('  \x1b[90mThis is a portfolio, not a real terminal.\x1b[0m');
        }, 1000);
      }, 1500);
    } else {
      term.writeln(`\r\n  rm: missing operand`);
    }
  },
};
